    19→CdsApiImpl::CdsApiImpl(const envoy::config::core::v3::ConfigSource& cds_config,
    20→                       const xds::core::v3::ResourceLocator* cds_resources_locator,
    21→                       ClusterManager& cm, Stats::Scope& scope,
    22→                       ProtobufMessage::ValidationVisitor& validation_visitor)
    23→    : Envoy::Config::SubscriptionBase<envoy::config::cluster::v3::Cluster>(validation_visitor,
    24→                                                                           "name"),
    25→      helper_(cm, "cds"), cm_(cm), scope_(scope.createScope("cluster_manager.cds.")) {
    26→  const auto resource_name = getResourceName();
    27→  if (cds_resources_locator == nullptr) {
    28→    subscription_ = THROW_OR_RETURN_VALUE(cm_.subscriptionFactory().subscriptionFromConfigSource(
    29→                                              cds_config, Grpc::Common::typeUrl(resource_name),
    30→                                              *scope_, *this, resource_decoder_, {}),
    31→                                          Config::SubscriptionPtr);
    32→  } else {
    33→    subscription_ = THROW_OR_RETURN_VALUE(
    34→        cm.subscriptionFactory().collectionSubscriptionFromUrl(
    35→            *cds_resources_locator, cds_config, resource_name, *scope_, *this, resource_decoder_),
    36→        Config::SubscriptionPtr);
