    40→absl::Status CdsApiImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& resources,
    41→                                        const std::string& version_info) {
    42→  auto all_existing_clusters = cm_.clusters();
    43→  // Exclude the clusters which CDS wants to add.
    44→  for (const auto& resource : resources) {
    45→    all_existing_clusters.active_clusters_.erase(resource.get().name());
    46→    all_existing_clusters.warming_clusters_.erase(resource.get().name());
    47→  }
    48→  Protobuf::RepeatedPtrField<std::string> to_remove_repeated;
    49→  for (const auto& [cluster_name, _] : all_existing_clusters.active_clusters_) {
    50→    UNREFERENCED_PARAMETER(_);
    51→    *to_remove_repeated.Add() = cluster_name;
    52→  }
    53→  for (const auto& [cluster_name, _] : all_existing_clusters.warming_clusters_) {
    54→    UNREFERENCED_PARAMETER(_);
    55→    // Do not add the cluster twice when the cluster is both active and warming.
    56→    if (!all_existing_clusters.active_clusters_.contains(cluster_name)) {
    57→      *to_remove_repeated.Add() = cluster_name;
    58→    }
    59→  }
    60→  return onConfigUpdate(resources, to_remove_repeated, version_info);
    61→}
    62→
    63→absl::Status
    64→CdsApiImpl::onConfigUpdate(const std::vector<Config::DecodedResourceRef>& added_resources,
    65→                           const Protobuf::RepeatedPtrField<std::string>& removed_resources,
    66→                           const std::string& system_version_info) {
    67→  auto exception_msgs =
    68→      helper_.onConfigUpdate(added_resources, removed_resources, system_version_info);
    69→  runInitializeCallbackIfAny();
    70→  if (!exception_msgs.empty()) {
    71→    return absl::InvalidArgumentError(
    72→        fmt::format("Error adding/updating cluster(s) {}", absl::StrJoin(exception_msgs, ", ")));
    73→  }
    74→  return absl::OkStatus();
    75→}
    76→
    77→void CdsApiImpl::onConfigUpdateFailed(Envoy::Config::ConfigUpdateFailureReason reason,
    78→                                      const EnvoyException*) {
    79→  ASSERT(Envoy::Config::ConfigUpdateFailureReason::ConnectionFailure != reason);
    80→  // We need to allow server startup to continue, even if we have a bad
    81→  // config.
    82→  runInitializeCallbackIfAny();
    83→}
    84→
    85→void CdsApiImpl::runInitializeCallbackIfAny() {
    86→  if (initialize_callback_) {
    87→    initialize_callback_();
    88→    initialize_callback_ = nullptr;
    89→  }
    90→}
