    89→bool isBlockingAdsCluster(const envoy::config::bootstrap::v3::Bootstrap& bootstrap,
    90→                          absl::string_view cluster_name) {
    91→  bool blocking_ads_cluster = false;
    92→  if (bootstrap.dynamic_resources().has_ads_config()) {
    93→    const auto& ads_config_source = bootstrap.dynamic_resources().ads_config();
    94→    // We only care about EnvoyGrpc, not GoogleGrpc, because we only need to delay ADS mux
    95→    // initialization if it uses an Envoy cluster that needs to be initialized first. We don't
    96→    // depend on the same cluster initialization when opening a gRPC stream for GoogleGrpc.
    97→    blocking_ads_cluster =
