   172→  bool canary() const override { return canary_; }
   173→  void canary(bool is_canary) override { canary_ = is_canary; }
   174→
   175→  // Metadata getter/setter.
   176→  //
   177→  // It's possible that the lock that guards the metadata will become highly contended (e.g.:
   178→  // endpoints churning during a deploy of a large cluster). A possible improvement
   179→  // would be to use TLS and post metadata updates from the main thread. This model would
   180→  // possibly benefit other related and expensive computations too (e.g.: updating subsets).
   181→  MetadataConstSharedPtr metadata() const override {
   182→    absl::ReaderMutexLock lock(&metadata_mutex_);
