795→bool ClusterManagerImpl::addOrUpdateCluster(const envoy::config::cluster::v3::Cluster& cluster,
   796→                                            const std::string& version_info) {
   797→  // First we need to see if this new config is new or an update to an existing dynamic cluster.
   798→  // We don't allow updates to statically configured clusters in the main configuration. We check
   799→  // both the warming clusters and the active clusters to see if we need an update or the update
   800→  // should be blocked.
   801→  const std::string& cluster_name = cluster.name();
   802→  const auto existing_active_cluster = active_clusters_.find(cluster_name);
   803→  const auto existing_warming_cluster = warming_clusters_.find(cluster_name);
   804→  const uint64_t new_hash = MessageUtil::hash(cluster);
   805→  if (existing_warming_cluster != warming_clusters_.end()) {
   806→    // If the cluster is the same as the warming cluster of the same name, block the update.
   807→    if (existing_warming_cluster->second->blockUpdate(new_hash)) {
   808→      return false;
   809→    }
   810→    // NB: https://github.com/envoyproxy/envoy/issues/14598
   811→    // Always proceed if the cluster is different from the existing warming cluster.
   812→  } else if (existing_active_cluster != active_clusters_.end() &&
   813→             existing_active_cluster->second->blockUpdate(new_hash)) {
   814→    // If there's no warming cluster of the same name, and if the cluster is the same as the active
   815→    // cluster of the same name, block the update.
   816→    return false;
   817→  }
   818→
   819→  if (existing_active_cluster != active_clusters_.end() ||
   820→      existing_warming_cluster != warming_clusters_.end()) {
   821→    if (existing_active_cluster != active_clusters_.end()) {
   822→      // The following init manager remove call is a NOP in the case we are already initialized.
   823→      // It's just kept here to avoid additional logic.
   824→      init_helper_.removeCluster(*existing_active_cluster->second);
   825→    }
   826→    cm_stats_.cluster_modified_.inc();
   827→  } else {
   828→    cm_stats_.cluster_added_.inc();
   829→  }
   830→
   831→  // There are two discrete paths here depending on when we are adding/updating a cluster.
   832→  // 1) During initial server load we use the init manager which handles complex logic related to
   833→  //    primary/secondary init, static/CDS init, warming all clusters, etc.
   834→  // 2) After initial server load, we handle warming independently for each cluster in the warming
   835→  //    map.
   836→  // Note: It's likely possible that all warming logic could be centralized in the init manager, but
   837→  //       a decision was made to split the logic given how complex the init manager already is. In
   838→  //       the future we may decide to undergo a refactor to unify the logic but the effort/risk to
   839→  //       do that right now does not seem worth it given that the logic is generally pretty clean
   840→  //       and easy to understand.
   841→  const bool all_clusters_initialized =
   842→      init_helper_.state() == ClusterManagerInitHelper::State::AllClustersInitialized;
   843→  // Preserve the previous cluster data to avoid early destroy. The same cluster should be added
   844→  // before destroy to avoid early initialization complete.
   845→  auto status_or_cluster = loadCluster(cluster, new_hash, version_info, /*added_via_api=*/true,
   846→                                       /*required_for_ads=*/false, warming_clusters_);
