   848→  const ClusterDataPtr previous_cluster = std::move(status_or_cluster.value());
   849→  auto& cluster_entry = warming_clusters_.at(cluster_name);
   850→  cluster_entry->cluster_->info()->configUpdateStats().warming_state_.set(1);
   851→  if (!all_clusters_initialized) {
   852→    ENVOY_LOG(debug, "add/update cluster {} during init", cluster_name);
   853→    init_helper_.addCluster(*cluster_entry);
   854→  } else {
   855→    ENVOY_LOG(debug, "add/update cluster {} starting warming", cluster_name);
