   858→      auto state_changed_cluster_entry = warming_clusters_.find(cluster_name);
   859→      state_changed_cluster_entry->second->cluster_->info()->configUpdateStats().warming_state_.set(
   860→          0);
   861→      onClusterInit(*state_changed_cluster_entry->second);
   862→    });
   863→  }
   864→
